window.__QUIZ_DATA__=[{"id":"objective>Economics>1994>1","subject":"Economics","year":"1994","type":"Objective","topic":"INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS","question":"The definition of Economics as \"the science which studies human behaviour as a relationship between ends and scarce means which have alternative uses\" was given by","images":[],"options":{"A":"Adam Smith","B":"David Ricardo","C":"Lionel Robbins","D":"Thomas R. Malthus"},"answer":"C","explanation":"The definition of Economics as \"the science which studies human behaviour as a relationship between ends and scarce means which have alternative uses\" was given by Lionel Robbins. This definition emphasizes the allocation of limited resources to satisfy various human wants, which is a fundamental concept in economics.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1994>2","subject":"Economics","year":"1994","type":"Objective","topic":"THEORY OF PRODUCTION : INTRODUCTION","question":"The concept of economic efficiency primarily implies","images":[],"options":{"A":"obtaining the maximum output from available resources at the lowest possible cost","B":"conserving our petroleum resources","C":"equity in the distribution of the nation's wealth","D":"producing without waste"},"answer":"A","explanation":"The concept of economic efficiency primarily implies obtaining the maximum output from available resources at the lowest possible cost. This is known as productive efficiency, where resources are utilized in the most effective way to produce goods and services.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1994>3","subject":"Economics","year":"1994","type":"Objective","topic":"BUSINESS ORGANISATION : PUBLIC CORPORATIONS","question":"Which of the following is true of NEPA as a public corporation in NIgeria? It is","images":[],"options":{"A":"a solar energy distributor","B":"a duopoly","C":"a monopolistically competitive industry","D":"a monopoly"},"answer":"D","explanation":"NEPA (National Electric Power Authority) in Nigeria is classified as a monopoly. A monopoly exists when a single firm is the sole provider of a product or service in a market, which is the case for NEPA in the electricity supply sector in Nigeria.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1994>4","subject":"Economics","year":"1994","type":"Objective","topic":"LABOUR MARKET AND UNEMPLOYMENT : THE CONCEPT OF UNEMPLOYMENT","question":"A situation of full employment exists when","images":[],"options":{"A":"every adult is employed","B":"all adults who can work are employed","C":"all persons who have attained the age of I5 years and above are employed","D":"all those who are able and eligible to work are employed"},"answer":"D","explanation":"A situation of full employment exists when all those who are able and eligible to work are employed. This does not mean that every adult is employed, as some may choose not to work or may be unable to work due to various reasons.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1994>5","subject":"Economics","year":"1994","type":"Objective","topic":"MONEY : FUNCTIONS OF MONEY","question":"Which of the following functions of money makes it possible for any person to provide for old age?","images":[],"options":{"A":"Medium of exchange","B":"Store of value","C":"Measure of value","D":"Unit of account"},"answer":"B","explanation":"The function of money that makes it possible for any person to provide for old age is the 'Store of value'. This function allows individuals to save money and preserve its value over time, enabling them to use it in the future for retirement or old age needs.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1994>6","subject":"Economics","year":"1994","type":"Objective","topic":"AGRICULTURE IN WEST AFRICA : ROLES","question":"The primary objective of the Agricultural Credit Guarantee Scheme is the provision of","images":[],"options":{"A":"guarantee for loans granted by banks for agricultural purposes","B":"agricultural inputs to facilitate credit from banks","C":"loans for every farmer","D":"agricultural products for farmers"},"answer":"A","explanation":"The primary objective of the Agricultural Credit Guarantee Scheme is to provide a guarantee for loans granted by banks for agricultural purposes. This scheme is designed to encourage banks to lend to farmers by reducing the risk associated with agricultural loans.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1994>7","subject":"Economics","year":"1994","type":"Objective","topic":"INDUSTRY & INDUSTRIALISATION : INTRODUCTION","question":"Which of the following is not an advantage of localization of industries?","images":[],"options":{"A":"Enjoyment of external economies","B":"Development of subsidiary industries","C":"Development of organized markets","D":"Growth of conurbation"},"answer":"D","explanation":"Growth of conurbation is not an advantage of localization of industries. While localization can lead to benefits such as external economies and the development of organized markets, conurbation refers to the merging of urban areas, which can lead to challenges such as congestion and pollution rather than advantages.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1994>8","subject":"Economics","year":"1994","type":"Objective","topic":"BUSINESS ORGANISATION : PUBLIC CORPORATIONS","question":"Which of the following is not an advantage of government ownership of enterprises?","images":[],"options":{"A":"More capital is provided","B":"Pricing policy may be in the interest of consumers","C":"Government workers may be indifferent towards the public","D":"Infrastructures are rapidly developed"},"answer":"C","explanation":"The statement that government workers may be indifferent towards the public is not an advantage of government ownership of enterprises. In fact, this can be a disadvantage, as it may lead to inefficiencies and a lack of responsiveness to consumer needs, unlike private enterprises that are driven by profit motives.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1994>9","subject":"Economics","year":"1994","type":"Objective","topic":"INTERNATIONAL TRADE : EXCHANGE RATE","question":"If the foreign exchange rate is #8 to \u20a41, then a bicycle bought for \u20a440 will cost","images":[],"options":{"A":"#15.00","B":"#60.00","C":"#100.00","D":"#250.00"},"answer":"C","explanation":"If the foreign exchange rate is #8 to \u20a41, then a bicycle bought for \u20a440 will cost #320.   This is calculated by multiplying the price in pounds by the exchange rate: \u20a440 x #8/\u20a41   = #320.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1994>10","subject":"Economics","year":"1994","type":"Objective","topic":"FINANCIAL INSTITUTION : COMMERCIAL BANKS","question":"All of the following are assets of a commercial bank except","images":[],"options":{"A":"cash","B":"bills discounted","C":"bank deposits","D":"investment"},"answer":"C","explanation":"Bank deposits are not considered assets of a commercial bank; rather, they are liabilities. Assets include cash, bills discounted, investments, and advances to customers, while deposits represent money owed to customers.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1994>11","subject":"Economics","year":"1994","type":"Objective","topic":"FINANCIAL INSTITUTION : CENTRAL BANK","question":"The Central Bank controls commercial banks through all the following except measures except","images":[],"options":{"A":"the use of directives","B":"the use of bank rate","C":"open market operations","D":"accepting deposits"},"answer":"D","explanation":"The Central Bank controls commercial banks through various measures, but accepting deposits is not a control measure. Instead, it is a function of commercial banks. The other options (directives, bank rate, open market operations, and demanding special deposits) are all tools used by the Central Bank to influence the banking system.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1994>12","subject":"Economics","year":"1994","type":"Objective","topic":"THE THEORY OF DEMAND : MEANING AND DETERMINANTS","question":"If a person supplements his current income by drawing on past savings in order to make both ends meet, he is said to be living","images":[],"options":{"A":"good life","B":"an average life","C":"on his savings","D":"a reckless life"},"answer":"C","explanation":"When a person draws on past savings to meet current expenses, they are said to be living on their savings. This indicates that they are using previously accumulated funds rather than current income to sustain their lifestyle.","marks":"1","difficulty":"1"},{"id":"objective>Economics>1994>13","subject":"Economics","year":"1994","type":"Objective","topic":"TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY","question":"Which of the following is not a set of measures of central tendency?","images":[],"options":{"A":"Mode and median","B":"Mean and median","C":"Mean and mode","D":"Median and percentage"},"answer":"D","explanation":"The median is a measure of central tendency, but 'median and percentage' does not represent a set of measures of central tendency. Percentages are not measures of central tendency; they are a way to express a number as a fraction of 100.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1994>14","subject":"Economics","year":"1994","type":"Objective","topic":"TOOLS FOR ECONOMIC ANALYSIS: REPRESENTATION OF DATA","question":"The diagram below is a","images":["data:image/jpeg;base64,"],"options":{"A":"bar chart","B":"pie chart","C":"ball chart","D":"histogram"},"answer":"B","explanation":"The diagram above represent a pie chart which is also known as circle chart. It is a graphical representation of data where the circle is divided into slices, each slice representing a proportion of the whole.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1994>15","subject":"Economics","year":"1994","type":"Objective","topic":"DISTRIBUTIVE TRADE : THE MIDDLEMEN","question":"Which of the following pairs can be referred to as middlemen?","images":[],"options":{"A":"Wholesalers and agents","B":"Retailers and consumers","C":"Consumers and agents","D":"Wholesalers and retailers"},"answer":"A","explanation":"Wholesalers and agents can be referred to as middlemen because they act as intermediaries between producers and retailers or consumers. They facilitate the distribution of goods and services, making them essential in the supply chain.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1994>16","subject":"Economics","year":"1994","type":"Objective","topic":"AGRICULTURE IN WEST AFRICA : INTRODUCTION","question":"Mono-product economies are those that","images":[],"options":{"A":"have rich cultural heritage","B":"produce only raw materials","C":"live on the exportation of their products","D":"produce one main commodity"},"answer":"D","explanation":"Mono-product economies are characterized by their production of one main commodity. This means that the economy relies heavily on a single product for its economic activities, which can lead to vulnerabilities if the demand for that product fluctuates.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1994>17","subject":"Economics","year":"1994","type":"Objective","topic":"MARKET STRUCTURE : IMPERFECT MARKET - MONOPOLY","question":"In the figure above, the broken line labelled PM is the Marginal Revenue Curve of a","images":["data:image/jpeg;base64,"],"options":{"A":"monopoly","B":"competitive firm","C":"state corporation","D":"partnership"},"answer":"A","explanation":"The Marginal Revenue Curve (MR) is typically associated with a monopoly, as monopolies are the only market structure where the MR curve is downward sloping and lies below the demand curve. This is due to the fact that a monopolist must lower the price to sell additional units, which affects the revenue generated from all units sold.","marks":"1","difficulty":"3"},{"id":"objective>Economics>1994>18","subject":"Economics","year":"1994","type":"Objective","topic":"THE THEORY OF DEMAND : DISTINCTION BETWEEN CHANGE IN QUANTITY DEMANDED AND CHANGE IN DEMAND","question":"A Nigeria household's demand curve for semovita is downward sloping because","images":[],"options":{"A":"the demand for semovita is high","B":"the local markets are flood with semovita","C":"semovita is produced in Nigeria","D":"the higher the price of semovita, the lower the quantity demanded"},"answer":"D","explanation":"A downward sloping demand curve indicates that as the price of semovita increases, the quantity demanded decreases. This is a fundamental principle of demand in economics, known as the law of demand, which states that there is an inverse relationship between price and quantity demanded.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1994>19","subject":"Economics","year":"1994","type":"Objective","topic":"THEORY OF CONSUMER BEHAVIOUR : CONCEPT","question":"To the economist, a stock of goods existing at a particular time and conforming to certain requirements such as having utility, money, value and being limited in supply, is known as","images":[],"options":{"A":"consumer goods","B":"products","C":"wealth","D":"commercial goods"},"answer":"C","explanation":"In economics, a stock of goods that has utility, monetary value, and is limited in supply is referred to as wealth. Wealth encompasses all valuable resources that can be owned and used to generate further economic benefits.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1994>20","subject":"Economics","year":"1994","type":"Objective","topic":"INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS","question":"The decision to consume more of one product will under normal circumstances imply that","images":[],"options":{"A":"more of another product will be consumed","B":"less of something else will be consumed","C":"no other product will be consumed","D":"decision-making is basic in Economics"},"answer":"B","explanation":"The decision to consume more of one product typically implies that less of another product will be consumed, due to the concept of opportunity cost. This principle states that choosing to allocate resources (such as time or money) to one option means forgoing the opportunity to use those resources for another option.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1994>21","subject":"Economics","year":"1994","type":"Objective","topic":"NATIONAL INCOME : CONCEPT","question":"The difference between the Gross Domestic Product and the Gross National Product is the","images":[],"options":{"A":"allowance for total depreciation","B":"total interest payment","C":"net income from abroad","D":"total tax and interest payments"},"answer":"C","explanation":"The difference between Gross Domestic Product (GDP) and Gross National Product (GNP) is primarily due to net income from abroad. GDP measures the total value of all goods and services produced within a country's borders, while GNP includes the value of goods and services produced by the residents of a country, regardless of where they are located, minus the income earned by foreign residents in the country. Therefore, the correct answer is 'net income from abroad'.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1994>22","subject":"Economics","year":"1994","type":"Objective","topic":"FINANCIAL INSTITUTION : COMMERCIAL BANKS","question":"One of the functions of a commercial bank is that it","images":[],"options":{"A":"is responsible for formulating monetary policies","B":"accepts demand and time deposits from customers","C":"is the lender of last resort","D":"is the banker of the government"},"answer":"B","explanation":"One of the primary functions of a commercial bank is to accept demand and time deposits from customers. This function allows banks to provide a safe place for individuals and businesses to store their money while also enabling them to lend out these deposits to generate interest income. Therefore, the correct answer is 'accepts demand and time deposits from customers'.","marks":"1","difficulty":"1"},{"id":"objective>Economics>1994>23","subject":"Economics","year":"1994","type":"Objective","topic":"DISTRIBUTIVE TRADE : THE MIDDLEMEN","question":"Which of the following is not a problem of distribution of goods in Nigeria?","images":[],"options":{"A":"Poor communication network","B":"Inadequate storage facilities","C":"Ignorance of consumers","D":"Dishonesty of middlemen"},"answer":"C","explanation":"Among the options provided, 'Ignorance of consumers' is not typically considered a problem of distribution of goods. The other options, such as poor communication network, inadequate storage facilities, dishonesty of middlemen, and inadequate market, directly affect the distribution process. Ignorance of consumers may affect purchasing decisions but does not directly impact the distribution logistics. Therefore, the correct answer is 'Ignorance of consumers'.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1994>24","subject":"Economics","year":"1994","type":"Objective","topic":"INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS","question":"Mr. Idowu need a television and a refrigerator. Each cost #500.00, the exact  amount he has. if Mr. Idowu buys the television, the refrigerator would be regarded as the","images":[],"options":{"A":"marginal cost","B":"inferior item","C":"opportunity cost","D":"supplementary item"},"answer":"C","explanation":"If Mr. Idowu buys the television for #500, the refrigerator, which he cannot afford now, represents the opportunity cost of his decision. Opportunity cost is defined as the value of the next best alternative that is forgone when making a choice. In this case, the refrigerator is the next best alternative that he cannot purchase because he chose to buy the television. Therefore, the correct answer is 'opportunity cost'.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1994>25","subject":"Economics","year":"1994","type":"Objective","topic":"INDUSTRY & INDUSTRIALISATION : INTRODUCTION","question":"Petro-chemical industries are located in Rivers State of Nigeria due to the presence of","images":[],"options":{"A":"a favourable climate","B":"coal deposits","C":"oil palm products","D":"oil deposits"},"answer":"D","explanation":"Petro-chemical industries are primarily located in Rivers State of Nigeria due to the presence of oil deposits. The availability of raw materials, such as crude oil, is crucial for the petrochemical industry, which processes these materials into various chemical products. Therefore, the correct answer is 'oil deposits'.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1994>26","subject":"Economics","year":"1994","type":"Objective","topic":"FINANCIAL INSTITUTION : CENTRAL BANK","question":"Foreign exchange control in Nigeria is enforced by the","images":[],"options":{"A":"Commercial Banks","B":"Mechant Banks","C":"Mortgage Banks","D":"Central Bank"},"answer":"D","explanation":"Foreign exchange control in Nigeria is enforced by the Central Bank. The Central Bank is responsible for regulating the country's monetary policy and managing the foreign exchange reserves, which includes implementing controls on foreign exchange transactions to stabilize the currency and manage the economy.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1994>27","subject":"Economics","year":"1994","type":"Objective","topic":"POPULATION : DETERMINANTS OF POPULATION SIZE","question":"The difference between the number of immigrants and emigrants is","images":[],"options":{"A":"internal mobility","B":"internal migration","C":"net migration","D":"marginal migration"},"answer":"C","explanation":"The difference between the number of immigrants (people coming into a country) and emigrants (people leaving a country) is known as net migration. This term reflects the overall change in population due to migration, indicating whether a country is gaining or losing population through migration.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1994>28","subject":"Economics","year":"1994","type":"Objective","topic":"THEORY OF PRODUCTION : FACTORS OF PRODUCTION","question":"Risk bearing and marginal control are the main functions of the","images":[],"options":{"A":"managing director","B":"manager","C":"entrepreneur","D":"chief executive"},"answer":"C","explanation":"Risk bearing and marginal control are primarily functions of the entrepreneur. An entrepreneur is someone who takes on the risk of starting and managing a business, making decisions that affect the business's operations and profitability. They are responsible for innovating and managing resources effectively.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1994>29","subject":"Economics","year":"1994","type":"Objective","topic":"THE CONCEPT OF COST & REVENUE : CONCEPT","question":"In the table below, the marginal cost when output is 2 units is,     Output Total Cost (#)1 202 563 964 1445 160","images":[],"options":{"A":"#16.00","B":"#20.00","C":"#36.00","D":"#40.00"},"answer":"C","explanation":"To find the marginal cost when output is 2 units, we calculate the change in total cost when output increases from 1 unit to 2 units.     The total cost at 1 unit is #20 and at 2 units is #56.     Therefore, the marginal cost is #56 - #20   = #36.00.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1994>30","subject":"Economics","year":"1994","type":"Objective","topic":"THEORY OF PRODUCTION : LAWS OF PRODUCTION","question":"If successive units of labour are added to a piece of land while capital and technology remain constant, a point will be reached in the level of production when each each additional unit of labour will add less to the output than previous units. This concept is known as the","images":[],"options":{"A":"productivity of labour","B":"law of diminishing marginal utility","C":"law of diminishing returns","D":"law of diminishing returns of a variable factor"},"answer":"C","explanation":"The concept described is known as the law of diminishing returns. This economic principle states that if one factor of production (like labor) is increased while other factors (like capital and technology) remain constant, the incremental output gained from each additional unit of that factor will eventually decrease. This is a fundamental concept in production theory.","marks":"1","difficulty":"3"},{"id":"objective>Economics>1994>31","subject":"Economics","year":"1994","type":"Objective","topic":"THEORY OF PRODUCTION : CONCEPTS OF PRODUCTION","question":"Fixed Unit of Land (hectares) Variable Unit of Labour  Total Output Marginal Product5110105225155 3 X 215 4 60145 5 73 135 6 82 Y  Which of the following pairs gives the values of X and Y in the table above?","images":[],"options":{"A":"X =20, Y = 6","B":"X = 10, Y = 10","C":"X = 38, Y = 9","D":"X = 46, Y = 9"},"answer":"D","explanation":"Since, average product is missing, then TP will be calculated by adding the 2nd unit + the MP 3rd unit.  TP = 25 + 21  = 46    MP = change in TP/change in variable unit  = 82 - 73/ 6 - 5  = 9","marks":"1","difficulty":"2"},{"id":"objective>Economics>1994>32","subject":"Economics","year":"1994","type":"Objective","topic":"THE CONCEPT OF COST & REVENUE : CONCEPT","question":"When a firm's total revenue is at the maximum, marginal revenue is","images":[],"options":{"A":"at the maximum","B":"negative","C":"zero","D":"positive"},"answer":"C","explanation":"When a firm's total revenue is at its maximum, the marginal revenue (MR) is zero. This is because marginal revenue is the additional revenue generated from selling one more unit of a good. At the maximum total revenue point, selling additional units does not increase total revenue, hence MR equals zero. This concept is fundamental in understanding revenue maximization in economics.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1994>33","subject":"Economics","year":"1994","type":"Objective","topic":"THEORY OF SUPPLY : ELASTICITY OF SUPPLY","question":"Under normal circumstances, a producer will bear the entire burden of taxation on his output if the","images":[],"options":{"A":"supply of his goods is more elastic than the demand","B":"demand for his product is completely elastic","C":"production of his commodities is subject to diminishing returns","D":"demand for his product is completely inelastic"},"answer":"D","explanation":"A producer will bear the entire burden of taxation on his output if the demand for his product is completely inelastic. This means that consumers will continue to buy the same quantity regardless of price changes, so the producer cannot pass the tax burden onto consumers. Therefore, the correct option is that the demand for his product is completely inelastic","marks":"1","difficulty":"3"},{"id":"objective>Economics>1994>34","subject":"Economics","year":"1994","type":"Objective","topic":"BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES","question":"Limited liability means that","images":[],"options":{"A":"the debts of a company can only be paid from its own assets","B":"the debts of a company are paid from business as well as private funds of the owners","C":"a company does not have to pay its debts","D":"the debts of a company must be paid from private funds only"},"answer":"A","explanation":"Limited liability means that the debts of a company can only be paid from its own assets, and the personal assets of the owners are protected. This is a fundamental principle of corporate law that limits the financial liability of the owners to the amount they have invested in the company. Therefore, the correct option is that the debts of a company can only be paid from its own assets.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1994>35","subject":"Economics","year":"1994","type":"Objective","topic":"THEORY OF PRODUCTION : FACTORS OF PRODUCTION","question":"Factory buildings, machinery and raw materials are known in Economics as","images":[],"options":{"A":"personal wealth","B":"social wealth","C":"government wealth","D":"business wealth"},"answer":"D","explanation":"Factory buildings, machinery, and raw materials are known in economics as business wealth. This term refers to the physical assets that a business uses to produce goods and services.","marks":"1","difficulty":"1"},{"id":"objective>Economics>1994>36","subject":"Economics","year":"1994","type":"Objective","topic":"THEORY OF PRODUCTION : FACTORS OF PRODUCTION","question":"Abstention from consumption enables capital to be produced . Such abstention is called","images":[],"options":{"A":"saving","B":"production","C":"accumulation","D":"factors of production"},"answer":"A","explanation":"Abstention from consumption refers to the act of saving, which allows resources to be set aside for future use, enabling capital to be produced. Saving is the correct term for this concept.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1994>37","subject":"Economics","year":"1994","type":"Objective","topic":"PUBLIC FINANCE : TAX","question":"Tax evasion in Economics means","images":[],"options":{"A":"false declaration of assets","B":"paying tax only as and when due","C":"declaration of assets","D":"tax payment according to income received"},"answer":"A","explanation":"Tax evasion refers to the illegal act of not paying taxes owed, often through false declaration of assets. This is a deliberate attempt to reduce tax liability.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1994>38","subject":"Economics","year":"1994","type":"Objective","topic":"MONEY : DEMAND FOR MONEY","question":"The Quantity Theory of Money states that an increase in the quantity of money would bring about","images":[],"options":{"A":"a geometrical rise in prices","B":"an unequal rise in prices","C":"a proportionate rise in prices","D":"an absolute rise in prices"},"answer":"C","explanation":"The Quantity Theory of Money posits that an increase in the money supply will lead to a proportionate increase in prices, assuming that the velocity of money and output remain constant.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1994>39","subject":"Economics","year":"1994","type":"Objective","topic":"NATIONAL INCOME : CONCEPT","question":"The magnitude of the national income of a country depends on all the following except the","images":[],"options":{"A":"quantity of natural resources available","B":"level of technical know-how","C":"mobility of labour","D":"level of productivity"},"answer":"C","explanation":"The magnitude of national income is influenced by various factors, but the mobility of labor is not a direct determinant of national income. It affects how resources are allocated but does not directly determine the income level itself.","marks":"1","difficulty":"2"},{"id":"objective>Economics>1994>40","subject":"Economics","year":"1994","type":"Objective","topic":"ECONOMIC INTEGRATION : OBJECTIVES, LEVELS OF AND FEATURES","question":"Under the ECOWAS agreement, a Nigerian can enter and stay in Ghana without a visa for a period of","images":[],"options":{"A":"14 days","B":"30 days","C":"60 days","D":"90 days"},"answer":"D","explanation":"Under the ECOWAS agreement, Nigerian citizens can enter and stay in Ghana without a visa for a period of 90 days.","marks":"1","difficulty":"1"}];